// Calculate Maximum Line-of-Sight Distance
// Based on Earth's curvature and antenna heights

CONSTANTS
 EarthRadius = 6371 // km

FUNCTION CalculateLOSDistance(height1, height2)
 // heights in meters, returns distance in km

 // Convert heights to km
 h1 = height1 / 1000
 h2 = height2 / 1000

 // Calculate distance using geometry
 // d = sqrt(2 * R * h1) + sqrt(2 * R * h2)
 d1 = SQRT(2 * EarthRadius * h1)
 d2 = SQRT(2 * EarthRadius * h2)

 totalDistance = d1 + d2
 RETURN totalDistance
END FUNCTION

// Example: Antenna heights 100m and 50m
PRINT CalculateLOSDistance(100, 50)
// Result: approximately 39.5 km

